import React from 'react';
import { useContextSelector } from 'use-context-selector';
import { ConfigContext } from '../ConfigContext';
import { Tooltip } from '../../tooltip';
import type { ConfigProviderContextType } from '../interface';

const defaultTextOverflowPopperSidecar: NonNullable<ConfigProviderContextType['textOverflowPopperSidecar']> = ({
  title,
  ...props
}) => <Tooltip title={title} checkOverflow {...props} />;

export function useTextOverflowPopperSidecar() {
  return useContextSelector(ConfigContext, o => o.textOverflowPopperSidecar) ?? defaultTextOverflowPopperSidecar;
}
